function CreateRoom({ onBack, onJoinRoom, user }) {
  const [roomName, setRoomName] = useState('My Project');
  const [language, setLanguage] = useState('javascript');
  const [loading, setLoading] = useState(false);
  const [createdRoom, setCreatedRoom] = useState(null);

  const handleCreateRoom = async () => {
    if (!user) {
      toast.error('Please login first');
      return;
    }

    setLoading(true);
    try {
      const roomId = Math.random().toString(36).substring(2, 10).toUpperCase();
      const roomData = {
        roomId,
        name: roomName,
        language,
        username: user.username,
        userId: user.id
      };
      
      setCreatedRoom(roomData);
      toast.success(`Room ${roomId} created!`);
      
      setTimeout(() => {
        onJoinRoom(roomId, user.username, user.id);
      }, 2000);
    } catch (error) {
      toast.error('Failed to create room');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <div className="auth-header">
          <button onClick={onBack} className="back-btn">
            <ArrowLeft size={18} />
            Back
          </button>
          <div className="logo-container">
            <FolderPlus className="logo-icon" />
            <h1>Create Room</h1>
            <p>Start a new collaborative session</p>
          </div>
        </div>

        <div className="auth-form">
          <div className="input-group">
            <label>Your Username</label>
            <input
              type="text"
              value={user?.username || 'Guest'}
              className="auth-input"
              disabled
            />
          </div>

          <div className="input-group">
            <label>Room Name</label>
            <input
              type="text"
              placeholder="Enter room name"
              value={roomName}
              onChange={(e) => setRoomName(e.target.value)}
              className="auth-input"
              disabled={loading}
            />
          </div>

          <div className="input-group">
            <label>Programming Language</label>
            <select
              value={language}
              onChange={(e) => setLanguage(e.target.value)}
              className="auth-input"
              disabled={loading}
            >
              {LANGUAGE_OPTIONS.map(lang => (
                <option key={lang.id} value={lang.id}>{lang.name}</option>
              ))}
            </select>
          </div>

          <button onClick={handleCreateRoom} className="btn btn-primary btn-full" disabled={loading}>
            {loading ? (
              <>
                <div className="loading-spinner" style={{ width: '20px', height: '20px', borderWidth: '2px' }}></div>
                Creating Room...
              </>
            ) : (
              <>
                <FolderPlus size={18} />
                Create Room
              </>
            )}
          </button>

          {createdRoom && (
            <div className="room-created" style={{ marginTop: '20px' }}>
              <p style={{ color: '#00d4aa', fontWeight: '600' }}>✓ Room Created Successfully!</p>
              <p style={{ margin: '8px 0' }}>Room Code: <strong>{createdRoom.roomId}</strong></p>
              <p className="text-muted" style={{ fontSize: '14px' }}>
                Share this code with your team members to invite them
              </p>
              <p className="text-primary" style={{ fontSize: '13px', marginTop: '8px' }}>
                Joining room automatically...
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

